// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}



// Helper function to map weather condition to icon name
function getWeatherIcon(condition: string): string {
  const conditionLower = (condition || '').toLowerCase();

  if (conditionLower.includes('sunny') || conditionLower.includes('clear')) {
    return 'sun';
  }
  if (conditionLower.includes('cloudy') || conditionLower.includes('cloud')) {
    return 'cloud';
  }
  if (conditionLower.includes('rainy') || conditionLower.includes('rain')) {
    return 'cloud-rain';
  }
  if (conditionLower.includes('snowy') || conditionLower.includes('snow')) {
    return 'cloud-snow';
  }
  if (conditionLower.includes('storm') || conditionLower.includes('thunder')) {
    return 'cloud-lightning';
  }
  if (conditionLower.includes('windy') || conditionLower.includes('wind')) {
    return 'wind';
  }
  if (conditionLower.includes('fog') || conditionLower.includes('mist')) {
    return 'cloud-fog';
  }
  // Default to cloud if condition is unknown
  return 'cloud';
}

export default function render(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with city and current weather */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1} color="var(--ggui-color-onSurface)">{props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
          </Text>
        </Stack>

        {/* Current weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack direction="horizontal" gap="var(--ggui-spacing-6)" align="center">
            {/* Temperature and condition */}
            <Stack gap="var(--ggui-spacing-4)" align="start">
              {/* Large temperature display */}
              <Text size="4xl" weight="bold" color="var(--ggui-color-onSurface)" align="left">
                {Math.round(props.temperature)}°{props.unit}
              </Text>

              {/* Condition with icon/emoji */}
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Icon name={getWeatherIcon(props.condition)} size={32} color="var(--ggui-color-primary-500)" />
                <Text size="lg" weight="medium" color="var(--ggui-color-onSurface)">
                  {props.condition}
                </Text>
              </Stack>
            </Stack>

            <Spacer size="flex" />

            {/* Humidity and Wind Speed details */}
            <Stack gap="var(--ggui-spacing-4)" align="end">
              <Stack gap="var(--ggui-spacing-2)">
                <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="droplets" size={18} color="var(--ggui-color-primary-500)" />
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                    Humidity
                  </Text>
                </Stack>
                <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.humidity}%
                </Text>
              </Stack>

              <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

              <Stack gap="var(--ggui-spacing-2)">
                <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="wind" size={18} color="var(--ggui-color-primary-500)" />
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                    Wind Speed
                  </Text>
                </Stack>
                <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.windSpeed} m/s
                </Text>
              </Stack>
            </Stack>
          </Stack>
        </Card>

        {/* 5-day forecast strip */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={3} color="var(--ggui-color-onSurface)">
            5-Day Forecast
          </Heading>

          <Row gap="var(--ggui-spacing-2)" wrap>
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => (
                <Card
                  key={index}
                  shadow="sm"
                  padding="var(--ggui-spacing-4)"
                  radius="md"
                  style={{ flex: '1 1 auto', minWidth: '100px' }}
                >
                  <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      {day.day || `Day ${index + 1}`}
                    </Text>

                    <Icon
                      name={getWeatherIcon(day.icon || '')}
                      size={28}
                      color="var(--ggui-color-primary-500)"
                    />

                    <Stack direction="horizontal" gap="var(--ggui-spacing-1)" align="center" justify="center">
                      <Text size="sm" weight="semibold" color="var(--ggui-color-onSurface)">
                        {day.high ? Math.round(day.high) : '—'}°{props.unit}
                      </Text>
                      <Text size="sm" color="var(--ggui-color-onSurfaceVariant)">
                        {day.low ? Math.round(day.low) : '—'}°{props.unit}
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              ))
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No forecast data available
              </Text>
            )}
           </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

