// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Render(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Email validation helper
  const validateEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Validate step 1 fields
  const validateStep1 = (): boolean => {
    let isValid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!validateEmail(email)) {
      setEmailError('Please enter a valid email address');
      isValid = false;
    } else {
      setEmailError('');
    }
    return isValid;
  };

  // Check if Next button should be disabled
  const isNextDisabled = useMemo(() => {
    if (currentStep === 1) {
      return !name.trim() || !email.trim() || !validateEmail(email);
    }
    if (currentStep === 2) {
      return !satisfaction;
    }
    return false;
  }, [currentStep, name, email, satisfaction]);

  // Handle next button
  const handleNext = () => {
    if (currentStep === 1) {
      if (!validateStep1()) return;
    }
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  };

  // Handle back button
  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  // Handle feature checkbox toggle
  const handleFeatureToggle = (feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  };

  // Handle final submission
  const handleSubmit = () => {
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments,
    });
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Progress Bar */}
        <Stack gap="var(--ggui-spacing-2)" style={{ width: '100%', maxWidth: '600px' }}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 4
          </Text>
          <Progress
            value={currentStep}
            max={4}
            variant="default"
            size="md"
          />
        </Stack>

        {/* Card with form content */}
        <Card shadow="md" padding="var(--ggui-spacing-8)" style={{ width: '100%', maxWidth: '600px' }}>
          {/* Step 1: Name and Email */}
          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Your Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your name"
                value={name}
                onChange={setName}
                error={nameError}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="Enter your email"
                value={email}
                onChange={setEmail}
                error={emailError}
                required
              />
            </Stack>
          )}

          {/* Step 2: Satisfaction Rating */}
          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>How Satisfied Are You?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: String(index + 1),
                  label: label,
                }))}
                direction="vertical"
              />
            </Stack>
          )}

          {/* Step 3: Feature Interests */}
          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Features of Interest</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Select the features you are interested in:
              </Text>
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => handleFeatureToggle(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          )}

          {/* Step 4: Comments */}
          {currentStep === 4 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Share any additional feedback (optional)"
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          )}
        </Card>

        {/* Navigation Buttons */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-4)" justify="center" style={{ width: '100%', maxWidth: '600px' }}>
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          {currentStep < 4 ? (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={isNextDisabled}
            >
              Next
            </Button>
          ) : (
            <Button
              variant="primary"
              onClick={handleSubmit}
            >
              Submit
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; dueDate?: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Kanban(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  // State for task board
  const [tasks, setTasks] = useState(props.tasks || []);
  const [expandedAddForm, setExpandedAddForm] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');
  const editInputRef = useRef<HTMLInputElement | null>(null);

  // Merge real-time updates from stream
  useEffect(() => {
    if (!taskChanged.latest) return;
    const { action, task } = taskChanged.latest;
    if (!task?.id) return;

    setTasks((prevTasks) => {
      const existingIndex = prevTasks.findIndex((t) => t.id === task.id);
      if (action === 'delete') {
        return prevTasks.filter((t) => t.id !== task.id);
      }
      if (existingIndex >= 0) {
        const updated = [...prevTasks];
        updated[existingIndex] = { ...updated[existingIndex], ...task };
        return updated;
      }
      if (action === 'create') {
        return [...prevTasks, task];
      }
      return prevTasks;
    });
  }, [taskChanged.latest]);

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof tasks> = {};
    props.columns?.forEach((col) => {
      grouped[col.id || ''] = [];
    });
    tasks.forEach((task) => {
      const col = task.column || 'todo';
      if (!(col in grouped)) grouped[col] = [];
      grouped[col].push(task);
    });
    return grouped;
  }, [tasks, props.columns]);

  // Calculate totals
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  // Handle task move
  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasks((prev) => {
        const updated = prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t));
        return updated;
      });
      taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    },
    [taskUpdate]
  );

  // Handle add task
  const handleAddTask = useCallback(
    (columnId: string) => {
      // Only allow adding tasks to 'todo' column
      if (columnId !== 'todo') return;
      if (!newTaskTitle.trim()) return;
      const newTask = {
        id: `task-${Date.now()}`,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: 'todo',
        assignee: '',
        dueDate: '',
      };
      setTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId: newTask.id, data: { column: 'todo', title: newTaskTitle, priority: newTaskPriority, assignee: '', dueDate: '' } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setExpandedAddForm(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  // Handle edit task
  const handleEditTask = useCallback(
    (taskId: string) => {
      if (!editTitle.trim()) return;
      setTasks((prev) =>
        prev.map((t) =>(t.id === taskId ? { ...t, title: editTitle } : t))
      );
      const editTask = tasks.find((t) => t.id === taskId);
      taskUpdate({ action: 'edit', taskId, data: { title: editTitle, priority: editTask?.priority || 'medium', assignee: editTask?.assignee || '', dueDate: editTask?.dueDate || '', column: editTask?.column || 'todo' } });
      setEditingTaskId(null);
      setEditTitle('');
    },
    [editTitle, tasks, taskUpdate]
  );

  // Priority badge color mapping
  const priorityVariant: Record<string, 'error' | 'warning' | 'success'> = {
    high: 'error',
    medium: 'warning',
    low: 'success',
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Card shadow="sm" padding="var(--ggui-spacing-4)">
          <Row align="center" justify="between">
            <Text variant="label">
              Total Tasks: <Text is="span" weight="semibold">{totalTasks}</Text> | Completed:{' '}
              <Text is="span" weight="semibold" color="var(--ggui-color-success-600, #16a34a)">{completedTasks}</Text>
            </Text>
          </Row>
        </Card>

        {/* Kanban Columns */}
        <Row gap="var(--ggui-spacing-4)" align="start">
          {props.columns?.map((column) => {
            const colId = column.id || '';
            const colTasks = tasksByColumn[colId] || [];
            return (
              <Card
                key={colId}
                shadow="sm"
                padding="var(--ggui-spacing-4)"
                style={{ flex: '1 1 300px', minHeight: '600px' }}
              >
                <Stack gap="var(--ggui-spacing-4)">
                  {/* Column Header */}
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={3} style={{ margin: 0 }}>
                      {column.name}
                    </Heading>
                    <Badge variant="primary" size="sm">
                      {colTasks.length}
                    </Badge>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-2)" />

                  {/* Task Cards */}
                  <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
                    {colTasks.map((task) => (
                       <Card
                        key={task.id}
                        shadow="sm"
                        padding="var(--ggui-spacing-2)"
                        border
                        radius="md"
                      >
                        <Stack gap="var(--ggui-spacing-2)">
                          {/* Task Title - Editable on double-click */}
                          {editingTaskId === task.id ? (
                            <Input
                              label=""
                              value={editTitle}
                              onChange={setEditTitle}
                              placeholder="Edit task title"
                              size="sm"
                              autoFocus
                            />
                          ) : (
                            <Text
                              variant="label"
                              weight="semibold"
                              as={Clickable}
                              onDoubleClick={() => {
                                setEditingTaskId(task.id || null);
                                setEditTitle(task.title || '');
                              }}
                              style={{ userSelect: 'none', cursor: 'pointer', padding: 'var(--ggui-spacing-1)' }}
                            >
                              {task.title}
                            </Text>
                            </Text>
                          <Row gap="var(--ggui-spacing-2)" align="center">
                            {task.priority && (
                              <Badge
                                variant={priorityVariant[task.priority] || 'default'}
                                size="sm"
                              >
                                {task.priority}
                              </Badge>
                            )}
                            {task.assignee && (
                              <Avatar name={task.assignee} size="sm" />
                            )}
                            {task.dueDate && (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                {new Date(task.dueDate).toLocaleDateString('en-US', {
                                  month: 'short',
                                  day: 'numeric',
                                })}
                              </Text>
                            )}
                          </Row>

                          {/* Edit & Move Controls */}
                          <Row gap="var(--ggui-spacing-2)" wrap>
