  const reviews = (Array.isArray(props.product.reviews) ? props.product.reviews : []) as Array<{ author?: string; rating?: number; text?: string; date?: string }>;

  // Computed values
  const isInStock = stock > 0;
  const maxQuantity = stock;
  const stockBadgeVariant = isInStock ? (stock > 10 ? 'success' : 'warning') : 'error';
  const stockBadgeText = isInStock ? (stock > 10 ? 'In Stock' : 'Low Stock') : 'Out of Stock';

  // State
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Handler functions
  const handleQuantityChange = (delta: number) => {
    setQuantity((prev) => {
      const newQty = prev + delta;
      return Math.max(1, Math.min(newQty, maxQuantity));
    });
  };

  const handleAddToCart = () => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
