  const [typingUsers, setTypingUsers] = useState<Record<string, boolean>>({});
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  // Add streamed messages to the message list
  useEffect(() => {
    if (message.latest) {
      setAllMessages(prev => [...prev, message.latest!]);
      scrollToBottom();
    }
  }, [message.latest, scrollToBottom]);

  // Update typing indicator state
  useEffect(() => {
    if (typing.latest) {
      const { sender, active } = typing.latest;
      if (sender) {
        setTypingUsers(prev => ({
          ...prev,
          [sender]: active || false
        }));
      }
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputText, timestamp });
      setInputText('');
      scrollToBottom();
    }
  }, [inputText, sendMessage, scrollToBottom]);

  // Handle Enter key to send
  const handleKeyDown = useCallback((e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  }, [handleSendMessage]);

  // Compute active typing users (excluding current user)
  const activeTypingUsers = useMemo(() => {
    return Object.entries(typingUsers)
      .filter(([, isTyping]) => isTyping)
      .map(([sender]) => sender)
      .filter(sender => sender !== props.currentUser);
  }, [typingUsers, props.currentUser]);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" direction="vertical" align="stretch" style={{ height: '100vh', display: 'flex' }}>
        {/* Header */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center" justify="between">
            <Stack direction="vertical" gap="var(--ggui-spacing-2)" align="start">
              <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}
              </Text>
            </Stack>
            {activeTypingUsers.length > 0 && (
              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                <Spinner size={16} color="var(--ggui-color-primary-600)" />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {activeTypingUsers.length === 1
                    ? `${activeTypingUsers[0]} is typing...`
                    : `${activeTypingUsers.join(', ')} are typing...`}
                </Text>
              </Stack>
            )}
          </Stack>
        </Card>

        {/* Messages */}
        <Card
          padding="var(--ggui-spacing-4)"
          shadow="sm"
          border
          style={{
            flex: 1,
            overflowY: 'auto',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-4)'
          }}
        >
          {allMessages.length === 0 ? (
            <Box
              style={{
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                flex: 1
              }}
            >
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" align="center">
                No messages yet. Start the conversation!
              </Text>
            </Box>
          ) : (
            allMessages.map((msg, idx) => {
              const isCurrentUser = msg.sender === props.currentUser;
              const showSenderName = idx === 0 || allMessages[idx - 1]?.sender !== msg.sender;

              return (
                <Box key={idx} style={{ display: 'flex', justifyContent: isCurrentUser ? 'flex-end' : 'flex-start' }}>
                  <Stack
                    direction="vertical"
                    gap="var(--ggui-spacing-2)"
                    align={isCurrentUser ? 'end' : 'start'}
                    style={{
                      maxWidth: '70%'
                    }}
                  >
                    {showSenderName && !isCurrentUser && (
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                        {msg.sender || 'Unknown'}
                      </Text>
                    )}
                    <Box
                      padding="var(--ggui-spacing-3)"
                      background={isCurrentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                      borderRadius="var(--ggui-shape-radius-md)"
                    >
                      <Text
                        variant="body"
                        color={isCurrentUser ? '#ffffff' : 'var(--ggui-color-onSurface)'}
                        style={{ wordWrap: 'break-word' }}
                      >
                        {msg.text || ''}
                      </Text>
                    </Box>
                    {msg.timestamp && (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" size="xs">
                        {new Date(msg.timestamp).toLocaleTimeString([], {
                          hour: '2-digit',
                          minute: '2-digit'
                        })}
                      </Text>
                    )}
                  </Stack>
                </Box>
              );
            })
          )}
          <div ref={messagesEndRef} />
        </Card>

        {/* Input Area */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="end">
            <TextArea
              label="Message"
              placeholder="Type your message... (Enter to send, Shift+Enter for new line)"
              value={inputText}
              onChange={setInputText}
              onKeyDown={handleKeyDown}
              rows={2}
              style={{
                flex: 1
              }}
            />
            <Button
              variant="primary"
              onClick={handleSendMessage}
              disabled={inputText.trim().length === 0}
              size="md"
              rightIcon={<Icon name="send" size={16} />}
            >
              Send
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
}

