// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Helper functions outside render component
const formatPrice = (price?: number): string => {
  return price !== undefined ? `$${price.toFixed(2)}` : 'N/A';
};

const getChangeColor = (change?: number): string => {
  if (change === undefined) return 'var(--ggui-color-onSurfaceVariant, #52525b)';
  return change >= 0 ? 'var(--ggui-color-success-600, #16a34a)' : 'var(--ggui-color-error-600, #dc2626)';
};

const getChangeBorderColor = (change?: number): string => {
  if (change === undefined) return 'var(--ggui-color-outline, #d4d4d8)';
  return change >= 0 ? 'var(--ggui-color-success-200, #bbf7d0)' : 'var(--ggui-color-error-200, #fecaca)';
};

const getArrowIcon = (change?: number): string => {
  if (change === undefined) return '';
  return change >= 0 ? '▲' : '▼';
};

export default function render(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: track merged stock data with live updates
  const [displayStocks, setDisplayStocks] = useState(props.stocks);
  const [lastUpdatedTime, setLastUpdatedTime] = useState<Date>(new Date());
  const updateTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Update timestamp whenever price updates arrive
  useEffect(() => {
    if (priceUpdate.latest) {
      setLastUpdatedTime(new Date());
      // Clear any existing timeout
      if (updateTimeoutRef.current) {
        clearTimeout(updateTimeoutRef.current);
      }
      // Reset update indicator after 500ms flash
      updateTimeoutRef.current = setTimeout(() => {
        updateTimeoutRef.current = null;
      }, 500);
    }
  }, [priceUpdate.latest]);

  // Merge incoming price updates with display stocks
  useEffect(() => {
    if (priceUpdate.latest) {
      setDisplayStocks(prev => {
        const updated = [...prev];
        const index = updated.findIndex(s => s.symbol === priceUpdate.latest?.symbol);
        if (index !== -1) {
          updated[index] = {
            ...updated[index],
            price: priceUpdate.latest.price ?? updated[index].price,
            change: priceUpdate.latest.change ?? updated[index].change,
            changePercent: priceUpdate.latest.changePercent ?? updated[index].changePercent,
          };
        }
        return updated;
      });
    }
  }, [priceUpdate.latest]);

  // Format last updated time
  const formattedLastUpdated = useMemo(() => {
    return lastUpdatedTime.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  }, [lastUpdatedTime]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" direction="vertical">
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">Market Watch</Heading>
          <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Last Updated:
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
              {formattedLastUpdated}
            </Text>
          </Stack>
        </Stack>

        {/* Stock Cards Grid - Responsive: 3 columns desktop, 1 mobile */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            gap: 'var(--ggui-spacing-6)',
          }}
        >
          {displayStocks.map((stock) => (
            <Card
              key={stock.symbol}
              padding="var(--ggui-spacing-4)"
              shadow="md"
              radius="lg"
              style={{
                borderColor: getChangeBorderColor(stock.change),
                borderWidth: '2px',
                borderStyle: 'solid',
                transition: 'box-shadow 300ms ease, border-color 300ms ease, box-shadow 300ms cubic-bezier(0.4, 0, 0.2, 1)',
                animation: updateTimeoutRef.current ? 'pulse 300ms ease-out' : 'none',
              }}
            >
              <Stack gap="var(--ggui-spacing-4)" direction="vertical">
                {/* Ticker Symbol - Large, Bold */}
                <Text
                  variant="body"
                  weight="bold"
                  size="2xl"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {stock.symbol || 'N/A'}
                </Text>

                {/* Company Name */}
                <Text
                  variant="bodySmall"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {stock.name || 'Unknown Company'}
                </Text>

                {/* Divider */}
                <Divider margin="var(--ggui-spacing-2)" />

                {/* Current Price */}
                <Stack direction="vertical" gap="var(--ggui-spacing-2)">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Current Price
                  </Text>
                  <Text
                    variant="body"
                    weight="semibold"
                    size="xl"
                    color="var(--ggui-color-onSurface, #18181b)"
                  >
                    {formatPrice(stock.price)}
                  </Text>
                </Stack>

                {/* Change Amount & Percentage with Arrow */}
                <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
                  <Text
                    variant="label"
                    color={getChangeColor(stock.change)}
                    weight="semibold"
                  >
                    {stock.change !== undefined ? (stock.change >= 0 ? '+' : '') : ''}
                    {stock.change !== undefined ? stock.change.toFixed(2) : 'N/A'}
                  </Text>
                  <Text
                    variant="label"
                    color={getChangeColor(stock.changePercent)}
                    weight="semibold"
                  >
                    {getArrowIcon(stock.changePercent)} {stock.changePercent !== undefined ? stock.changePercent.toFixed(2) : 'N/A'}%
                  </Text>
                </Stack>
              </Stack>
            </Card>
          ))}
        </Box>
      </Stack>
    </Container>
  );
}

// CSS animation keyframes for flash highlight
const style = document.createElement('style');
style.textContent = `
  @keyframes pulse {
    0% { box-shadow: 0 0 0 0 rgba(34, 197, 94, 0.7); }
    50% { box-shadow: 0 0 0 10px rgba(34, 197, 94, 0); }
    100% { box-shadow: 0 0 0 0 rgba(34, 197, 94, 0); }
  }
`;
if (typeof document !== 'undefined' && !document.querySelector('style[data-pulse]')) {
  style.setAttribute('data-pulse', 'true');
  document.head.appendChild(style);
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };

export default function render(props: Props) {
  // State and hooks
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState(props.initialProfile.name || '');
  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || props.avatarOptions[0] || '');
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');
  const complete = useAction<ActionCompletePayload>('complete');

  // Validation functions
  const isValidEmail = (val: string) => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(val);
  };

  // Determine if Next button should be disabled
  const isStep1Valid = name.trim() !== '' && email.trim() !== '' && isValidEmail(email) && avatar !== '';
  const isStep2Valid = role !== '';
  const canProceedToNext = currentStep === 1 ? isStep1Valid : currentStep === 2 ? isStep2Valid : true;

  const handleNext = () => {
    if (currentStep < 3) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleComplete = () => {
    complete({
      name,
      email,
      avatar,
      role,
      emailNotifications,
      theme,
    });
  };

  const progressPercentage = (currentStep / 3) * 100;

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="center">
        {/* Step Indicator */}
        <Stack gap="var(--ggui-spacing-4)" align="center" style={{ width: '100%', maxWidth: '600px' }}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {currentStep} of 3
          </Text>
          <Progress value={progressPercentage} max={100} size="md" />
        </Stack>

        {/* Step Content Card */}
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg" style={{ width: '100%', maxWidth: '600px' }}>
          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Profile Setup
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Let's start by getting to know you.
              </Text>

              {/* Name Input */}
              <Input
                label="Full Name"
                placeholder="Jane Doe"
                value={name}
                onChange={setName}
                required
                error={name.trim() === '' && name !== '' ? 'Name is required' : ''}
              />

              {/* Email Input */}
              <Input
                label="Email Address"
                type="email"
                placeholder="jane@example.com"
                value={email}
                onChange={setEmail}
                required
                error={
                  email.trim() === '' ? 'Email is required' : !isValidEmail(email) ? 'Please enter a valid email address' : ''
                }
              />

              {/* Avatar Selection */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" as="span">
                  Choose Avatar <span style={{ color: 'var(--ggui-color-error-500, #ef4444)' }}>*</span>
                </Text>
                <Row gap="var(--ggui-spacing-4)" align="center">
                  {props.avatarOptions.map((opt) => (
                    <Box
                      key={opt}
                      as={Clickable}
                      onClick={() => setAvatar(opt)}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="8px"
                      background={
                        avatar === opt
                          ? 'var(--ggui-color-primary-100, #e0f2fe)'
                          : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
                      }
                      style={{
                        border:
                          avatar === opt
                            ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                            : '2px solid var(--ggui-color-outline, #d4d4d8)',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                      }}
                    >
                      <Text style={{ fontSize: '32px' }}>{opt}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Preferences
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Customize your experience.
              </Text>

              {/* Role Selection */}
              <Select
                label="Role"
                value={role}
                onChange={setRole}
                options={props.roleOptions.map((r) => ({ value: r, label: r }))}
                placeholder="Select your role"
                required
                error={role === '' && currentStep === 2 ? 'Role is required' : ''}
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Email Notifications"
                checked={emailNotifications}
                onChange={setEmailNotifications}
                size="md"
              />

              {/* Theme Preference */}
              <RadioGroup
                label="Theme Preference"
                value={theme}
                onChange={setTheme}
                options={[
                  { value: 'light', label: 'Light' },
                  { value: 'dark', label: 'Dark' },
                ]}
                direction="horizontal"
              />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
                Review & Confirm
              </Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Please review your information before completing setup.
              </Text>

              <Divider />

              {/* Summary */}
              <Stack gap="var(--ggui-spacing-4)">
                {/* Profile Section */}
                <Stack gap="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Profile
                  </Text>
                  <Row gap="var(--ggui-spacing-4)" align="start">
                    <Box>
                      <Text style={{ fontSize: '48px' }}>{avatar}</Text>
                    </Box>
                    <Stack gap="var(--ggui-spacing-2)" style={{ flex: 1 }}>
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Name
                        </Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                          {name}
                        </Text>
                      </Stack>
                      <Stack gap="var(--ggui-spacing-1)">
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          Email
                        </Text>
                        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)" weight="semibold">
                          {email}
                        </Text>
                      </Stack>
                    </Stack>
                  </Row>
                </Stack>

                <Divider />

                {/* Preferences Section */}
                <Stack gap="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurface, #18181b)">
                    Preferences
                  </Text>
                  <Stack gap="var(--ggui-spacing-2)">
                    <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Role
                      </Text>
                      <Badge variant="primary" size="sm">
                        {role}
                      </Badge>
                    </Row>
                    <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Email Notifications
                      </Text>
                      <Badge
                        variant={emailNotifications ? 'success' : 'default'}
                        size="sm">
                        {emailNotifications ? 'Enabled' : 'Disabled'}
                      </Badge>
                    </Row>
                    <Row gap="var(--ggui-spacing-2)" justify="between" align="center">
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        Theme
                      </Text>
                      <Badge variant="primary" size="sm">
                        {theme.charAt(0).toUpperCase() + theme.slice(1)}
                      </Badge>
                    </Row>
                  </Stack>
                </Stack>
              </Stack>
            </Stack>
          )}
        </Card>

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-4)" justify="center" style={{ width: '100%', maxWidth: '600px' }}>
          <Button
            variant="outline"
            size="md"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>

          {currentStep < 3 && (
            <Button
              variant="primary"
              size="md"
              onClick={handleNext}
              disabled={!canProceedToNext}
            >
              Next
            </Button>
          )}

          {currentStep === 3 && (
            <Button
              variant="primary"
              size="md"
              onClick={handleComplete}
            >
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
